# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

Prevent path traversal.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    public class FileController : ControllerBase
    {
        [HttpGet("files/{filename}")]
        public async Task<IActionResult> GetFile(string filename)
        {
            // Prevent path traversal by checking if the file is within the uploads folder
            if (!Path.IsPathRooted(filename))
            {
                return BadRequest("Invalid file name");
            }

            // Get the full path of the file to serve
            var filePath = Path.Combine(Directory.GetCurrentDirectory(), "uploads", filename);

            // Check if the file exists and is within the uploads folder
            if (!File.Exists(filePath) || !filePath.StartsWith("uploads"))
            {
                return NotFound();
            }

            // Get the content type of the file based on its extension
            var contentType = MimeMapping.GetMimeMapping(filename);

            // Return the file as a stream with the appropriate content type
            return File(File.OpenRead(filePath), contentType, filename);
        }
    }
}